    if (this.isSelected(format)) {
      this.selectedFormats = this.selectedFormats.filter(f => f !== format);
    } else {
      this.selectedFormats = [...this.selectedFormats, format];
    }
  }

  get activeCount() {
    return this.selectedFormats.length;
  }

  <template>
    <div class="flex gap-2 flex-wrap">
      {{#each this.allFormats as |format|}}
        <button
          {{on "click" (fn this.toggleFormat format)}}
          class="px-3 py-1 rounded-full border {{if (this.isSelected format) 'bg-blue-600 text-white' 'bg-white text-gray-700'}}"
        >
          {{format}}
        </button>
      {{/each}}
    </div>
    <p>{{this.activeCount}} format(s) selected</p>
  </template>
}
```
Store selected tags in a `@tracked` array. Toggle by filtering (remove) or spreading (add). Note that `isSelected` is a regular method (not a getter) because it takes an argument — call it using `(this.isSelected format)` syntax in the template.

