export default class PlayerStatsTableComponent extends Component {
  @tracked sortColumn = 'runs';
  @tracked sortDir = 'desc';

  @action
  sortBy(column) {
    if (this.sortColumn === column) {
      this.sortDir = this.sortDir === 'desc' ? 'asc' : 'desc';
    } else {
      this.sortColumn = column;
      this.sortDir = 'desc';
    }
