      <input value={{this.query}} {{on "input" (fn (mut this.query) (get-value))}} class="border rounded px-3 py-2 flex-1" />
      <button {{on "click" this.search}}>Search</button>
      <button {{on "click" this.clearSearch}}>Clear</button>
    </div>
    {{#each this.displayResults as |match|}}
      <p>{{match.name}}</p>
    {{/each}}
  </template>
