  get isValid() {
    return !this.hasError && this.runs !== '';
  }

  @action
  onRunsChange(event) {
    const value = event.target.value;
    this.runs = value;
    const num = Number(value);
    if (value === '') {
      this.errorMessage = 'Runs cannot be empty';
    } else if (!Number.isInteger(num) || num < 0) {
      this.errorMessage = 'Runs must be a non-negative integer';
    } else if (num > 36) {
      this.errorMessage = 'Runs per delivery cannot exceed 36';
    } else {
      this.errorMessage = '';
    }
  }

  <template>
    <input
      type="number"
      value={{this.runs}}
      {{on "input" this.onRunsChange}}
      class="border rounded px-3 py-2 {{if this.hasError 'border-red-500' 'border-gray-300'}}"
    />
    {{#if this.hasError}}
      <p class="text-red-600 text-sm mt-1">{{this.errorMessage}}</p>
    {{/if}}
  </template>
