    <input value={{this.position}} {{on "input" this.updatePosition}} class="border rounded px-3 py-2" />
    {{#if this.isDirty}}
      <div class="flex gap-2 mt-2">
        <button {{on "click" this.save}} class="btn-primary">Save</button>
        <button {{on "click" this.discard}}>Discard</button>
      </div>
    {{/if}}
  </template>
}
```
Set `isDirty = true` in any change handler and reset it to `false` after a successful save or discard. Show save/discard buttons only when `isDirty` is true, preventing accidental no-op saves and providing a clear UX signal.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchEditFormComponent extends Component {
  @tracked isDirty = false;
  @tracked formData = {
    homeTeam: this.args.match?.homeTeam ?? '',
    awayTeam: this.args.match?.awayTeam ?? '',
    venue: this.args.match?.venue ?? '',
    format: this.args.match?.format ?? 'T20',
