      <input value={{this.formData.homeTeam}} {{on "input" (fn this.updateField 'homeTeam')}} placeholder="Home Team" />
      <input value={{this.formData.awayTeam}} {{on "input" (fn this.updateField 'awayTeam')}} placeholder="Away Team" />
      <input value={{this.formData.venue}} {{on "input" (fn this.updateField 'venue')}} placeholder="Venue" />
    </fieldset>
    <button {{on "click" this.saveMatch}} disabled={{not this.isDirty}} class="mt-3 btn-primary">
      {{if this.isDirty 'Save Changes' 'No Changes'}}
    </button>
  </template>
}
```
A combined `updateField` action handles both the data update and dirty marking in one call. Using `{{fn this.updateField 'fieldName'}}` from the template avoids writing separate actions per field. The save button's label and disabled state both respond to `isDirty`.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class TournamentEditorComponent extends Component {
  @tracked tournamentName = this.args.tournament?.name ?? '';
  @tracked isDirty = false;
  @tracked isSaving = false;
  @tracked saveError = '';

  @action
  onNameChange(event) {
    this.tournamentName = event.target.value;
    this.isDirty = true;
  }

  @action
  async save() {
    if (!this.isDirty) return;
    this.isSaving = true;
    this.saveError = '';
    try {
      await this.args.onSave?.({ name: this.tournamentName });
      this.isDirty = false; // reset only on success
    } catch (err) {
      this.saveError = err.message ?? 'Save failed';
    } finally {
      this.isSaving = false;
    }
  }

  <template>
    <input value={{this.tournamentName}} {{on "input" this.onNameChange}} class="border rounded px-3 py-2" />
    {{#if this.saveError}}
      <p class="text-red-600 text-sm">{{this.saveError}}</p>
    {{/if}}
    <button
      {{on "click" this.save}}
      disabled={{or this.isSaving (not this.isDirty)}}
      class="btn-primary"
    >
      {{if this.isSaving 'Saving...' 'Save'}}
    </button>
  </template>
}
```
Reset `isDirty` inside the `try` block (after a successful save) — not in `finally`. If the save fails, `isDirty` should remain `true` so the user knows their changes weren't persisted. The `isSaving` flag prevents double-submits during the async operation.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class UndoScoreComponent extends Component {
  @tracked runs = 0;
  @tracked wickets = 0;
  @tracked history = [];

  get canUndo() {
    return this.history.length > 0;
  }

  #saveSnapshot() {
    this.history = [...this.history, { runs: this.runs, wickets: this.wickets }];
  }

  @action
  addRun() {
    this.#saveSnapshot();
    this.runs = this.runs + 1;
  }

  @action
  addWicket() {
    this.#saveSnapshot();
    this.wickets = this.wickets + 1;
  }

  @action
  undo() {
    if (!this.canUndo) return;
    const previous = this.history[this.history.length - 1];
    this.history = this.history.slice(0, -1);
    this.runs = previous.runs;
    this.wickets = previous.wickets;
  }

  <template>
    <p class="text-2xl">{{this.runs}}/{{this.wickets}}</p>
    <button {{on "click" this.addRun}}>+Run</button>
    <button {{on "click" this.addWicket}}>+Wicket</button>
    <button {{on "click" this.undo}} disabled={{not this.canUndo}}>Undo</button>
    <p class="text-sm text-gray-400">History: {{this.history.length}} steps</p>
  </template>
}
```
Save a snapshot (plain object) to the `@tracked` history array before each change. Undo by popping the last snapshot and restoring state from it. Use a private method `#saveSnapshot()` to avoid duplicating the snapshot logic. Spread the array when adding to maintain immutability.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class InningsEditorWithUndoComponent extends Component {
  @tracked score = { runs: 0, wickets: 0, overs: 0 };
  @tracked history = [];

  get canUndo() { return this.history.length > 0; }
  get undoStepsLabel() { return `${this.history.length} undo step(s) available`; }

  #push() {
    this.history = [...this.history, { ...this.score }];
  }

  @action
  addRuns(amount) {
    this.#push();
    this.score = { ...this.score, runs: this.score.runs + amount };
  }

  @action
  undo() {
    if (!this.canUndo) return;
    const prev = this.history.at(-1);
    this.history = this.history.slice(0, -1);
    this.score = { ...prev };
  }

  @action
  resetAll() {
    this.score = { runs: 0, wickets: 0, overs: 0 };
    this.history = [];
  }

  <template>
    <p class="text-2xl font-bold">{{this.score.runs}}/{{this.score.wickets}}</p>
    <button {{on "click" (fn this.addRuns 1)}}>+1</button>
    <button {{on "click" (fn this.addRuns 4)}}>+4</button>
    <button {{on "click" (fn this.addRuns 6)}}>+6</button>
    <button {{on "click" this.undo}} disabled={{not this.canUndo}}>↩ Undo</button>
    <button {{on "click" this.resetAll}}>Reset</button>
    <p class="text-xs text-gray-400">{{this.undoStepsLabel}}</p>
  </template>
}
```
Use `Array.prototype.at(-1)` (ES2022) to access the last element. Use `.slice(0, -1)` to create a new array without the last item. Always spread the snapshot when restoring: `this.score = { ...prev }` ensures a new object reference triggers reactivity.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MatchRegistrationWizardComponent extends Component {
  steps = ['Team Info', 'Match Details', 'Venue & Date', 'Confirm'];
  @tracked currentStep = 0;

  get isFirstStep() { return this.currentStep === 0; }
  get isLastStep() { return this.currentStep === this.steps.length - 1; }
  get currentStepName() { return this.steps[this.currentStep]; }
  get progressPercent() { return ((this.currentStep / (this.steps.length - 1)) * 100).toFixed(0); }

  @action
  nextStep() {
    if (!this.isLastStep) this.currentStep = this.currentStep + 1;
  }

  @action
  prevStep() {
    if (!this.isFirstStep) this.currentStep = this.currentStep - 1;
  }

  @action
  goToStep(index) {
    if (index >= 0 && index < this.steps.length) {
      this.currentStep = index;
    }
  }

  <template>
    <div class="mb-4">
      <div class="flex gap-2">
        {{#each this.steps as |step index|}}
          <button
            {{on "click" (fn this.goToStep index)}}
            class="px-2 py-1 text-sm rounded {{if (eq index this.currentStep) 'bg-blue-600 text-white' 'bg-gray-100'}}"
          >{{step}}</button>
        {{/each}}
      </div>
      <div class="w-full bg-gray-200 h-1 mt-2"><div class="bg-blue-600 h-1" style="width: {{this.progressPercent}}%"></div></div>
    </div>
    <p class="font-bold">Step {{this.currentStep}}: {{this.currentStepName}}</p>
    <div class="flex gap-2 mt-4">
      <button {{on "click" this.prevStep}} disabled={{this.isFirstStep}}>Back</button>
      <button {{on "click" this.nextStep}} disabled={{this.isLastStep}}>Next</button>
    </div>
  </template>
}
```
A zero-based step index provides clean array access. Boundary getters (`isFirstStep`, `isLastStep`) keep actions and template logic simple. A progress bar width derived from step index gives visual feedback without extra state.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class ValidatedWizardComponent extends Component {
  @tracked currentStep = 0;
  @tracked teamName = '';
  @tracked playerCount = '';
  @tracked venue = '';

  get stepIsValid() {
    switch (this.currentStep) {
      case 0: return this.teamName.trim().length > 0;
      case 1: return Number(this.playerCount) >= 11;
      case 2: return this.venue.trim().length > 0;
      default: return true;
    }
  }

  @action
  nextStep() {
    if (this.stepIsValid && this.currentStep < 2) {
      this.currentStep = this.currentStep + 1;
    }
  }

  @action
  prevStep() {
    if (this.currentStep > 0) {
      this.currentStep = this.currentStep - 1;
    }
  }

  <template>
    <p>Step {{this.currentStep}}</p>
    {{#if (eq this.currentStep 0)}}<input value={{this.teamName}} {{on "input" (fn (mut this.teamName) (get-value))}} placeholder="Team name" />{{/if}}
    {{#if (eq this.currentStep 1)}}<input type="number" value={{this.playerCount}} {{on "input" (fn (mut this.playerCount) (get-value))}} placeholder="Player count" />{{/if}}
    {{#if (eq this.currentStep 2)}}<input value={{this.venue}} {{on "input" (fn (mut this.venue) (get-value))}} placeholder="Venue" />{{/if}}
    <div class="flex gap-2 mt-3">
      <button {{on "click" this.prevStep}} disabled={{eq this.currentStep 0}}>Back</button>
      <button {{on "click" this.nextStep}} disabled={{not this.stepIsValid}}>Next</button>
    </div>
  </template>
}
```
Gate `nextStep` with a `stepIsValid` getter that uses a `switch` to check the relevant field for each step. This keeps navigation actions clean and validation logic centralized. The Next button is `disabled` when the current step is not valid.

