import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class FieldingPositionSelectorComponent extends Component {
  positions = ['Slip', 'Gully', 'Point', 'Cover', 'Mid-off', 'Mid-on', 'Square leg', 'Fine leg'];
  @tracked selected = [];

  isChecked(position) {
    return this.selected.includes(position);
  }

  get selectedCount() {
    return this.selected.length;
  }

  @action
  onCheckboxChange(position, event) {
    if (event.target.checked) {
      this.selected = [...this.selected, position];
    } else {
      this.selected = this.selected.filter(p => p !== position);
    }
  }

  <template>
    <p>Selected: {{this.selectedCount}} positions</p>
    <div class="grid grid-cols-2 gap-2">
      {{#each this.positions as |position|}}
        <label class="flex gap-2 items-center">
          <input
            type="checkbox"
            checked={{this.isChecked position}}
            {{on "change" (fn this.onCheckboxChange position)}}
          />
          {{position}}
        </label>
      {{/each}}
    </div>
    <p class="text-sm mt-2">{{this.selected.join ', '}}</p>
  </template>
}
```
Store selections as a `@tracked` string array. On check, spread-add; on uncheck, filter-remove. The `checked` attribute is controlled by the `isChecked` method so the UI stays in sync. `this.selected.join ', '` displays the selection summary.

