import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class TournamentFormatSelectorComponent extends Component {
  formats = [
    { id: 't20', label: 'T20' },
    { id: 'odi', label: 'ODI' },
    { id: 'test', label: 'Test' },
    { id: 't10', label: 'T10' },
    { id: 'hundred', label: 'The Hundred' },
  ];
  @tracked enabledFormats = ['t20', 'odi'];

  isEnabled(id) {
    return this.enabledFormats.includes(id);
  }

  get enabledCount() {
    return this.enabledFormats.length;
  }

  @action
  toggleFormat(id) {
    if (this.isEnabled(id)) {
      this.enabledFormats = this.enabledFormats.filter(f => f !== id);
    } else {
      this.enabledFormats = [...this.enabledFormats, id];
    }
  }

  <template>
    <p>{{this.enabledCount}} format(s) enabled</p>
    {{#each this.formats as |format|}}
      <label class="flex gap-2">
        <input
          type="checkbox"
          checked={{this.isEnabled format.id}}
          {{on "change" (fn this.toggleFormat format.id)}}
        />
        {{format.label}}
      </label>
    {{/each}}
  </template>
}
```
A single `toggleFormat` action handles both add and remove by checking `includes`. Pass the ID (not the event) via `{{fn}}` — the action doesn't need the event object since it performs a toggle, not reading `event.target.checked`.

